# Category: datastore_security


import mysql.connector
import os
import sys
import re


def validate_file_path(file_path):
    """Validate the file path to prevent path traversal and injection attacks."""
    # Resolve to absolute path
    abs_path = os.path.realpath(file_path)
    
    # Define allowed directories for file imports
    allowed_directories = [
        os.path.realpath('/var/data/imports'),
        os.path.realpath('/tmp/etl'),
        os.path.realpath(os.path.join(os.getcwd(), 'data')),
    ]
    
    # Check if the resolved path is within an allowed directory
    is_allowed = any(
        abs_path.startswith(allowed_dir + os.sep) or abs_path == allowed_dir
        for allowed_dir in allowed_directories
    )
    
    if not is_allowed:
        raise ValueError(
            f"File path '{abs_path}' is not within allowed directories: {allowed_directories}"
        )
    
    # Check that the file actually exists
    if not os.path.isfile(abs_path):
        raise FileNotFoundError(f"File not found: {abs_path}")
    
    # Check file extension
    allowed_extensions = {'.csv', '.tsv', '.txt', '.dat'}
    _, ext = os.path.splitext(abs_path)
    if ext.lower() not in allowed_extensions:
        raise ValueError(f"File extension '{ext}' is not allowed. Allowed: {allowed_extensions}")
    
    # Reject any path containing suspicious characters that could enable SQL injection
    # Only allow alphanumeric, underscores, hyphens, dots, and path separators
    basename = os.path.basename(abs_path)
    if not re.match(r'^[\w\-. ]+$', basename):
        raise ValueError(f"Filename contains invalid characters: {basename}")
    
    return abs_path


def validate_table_name(table_name):
    """Validate table name to prevent SQL injection."""
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', table_name):
        raise ValueError(f"Invalid table name: {table_name}")
    if len(table_name) > 64:
        raise ValueError("Table name too long (max 64 characters)")
    return table_name


def validate_database_name(db_name):
    """Validate database name to prevent SQL injection."""
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', db_name):
        raise ValueError(f"Invalid database name: {db_name}")
    if len(db_name) > 64:
        raise ValueError("Database name too long (max 64 characters)")
    return db_name


def get_db_connection(host, user, password, database, port=3306):
    """Create a MySQL connection with local_infile enabled."""
    try:
        database = validate_database_name(database)
        connection = mysql.connector.connect(
            host=host,
            user=user,
            password=password,
            database=database,
            port=port,
            allow_local_infile=True,
            connection_timeout=30,
        )
        return connection
    except mysql.connector.Error as e:
        print(f"Error connecting to MySQL: {e}")
        raise


def check_local_infile_enabled(connection):
    """Check if local_infile is enabled on the MySQL server."""
    cursor = connection.cursor()
    try:
        cursor.execute("SHOW GLOBAL VARIABLES LIKE 'local_infile'")
        result = cursor.fetchone()
        if result and result[1].upper() == 'ON':
            print("local_infile is enabled on the server.")
            return True
        else:
            print("WARNING: local_infile is NOT enabled on the server.")
            print("Enable it with: SET GLOBAL local_infile = 1;")
            return False
    finally:
        cursor.close()


def get_table_columns(connection, table_name):
    """Retrieve column names for a given table."""
    table_name = validate_table_name(table_name)
    cursor = connection.cursor()
    try:
        cursor.execute(
            "SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS "
            "WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = %s "
            "ORDER BY ORDINAL_POSITION",
            (table_name,)
        )
        columns = [row[0] for row in cursor.fetchall()]
        return columns
    finally:
        cursor.close()


def bulk_import_file(
    connection,
    file_path,
    table_name,
    field_delimiter=',',
    line_delimiter='\\n',
    enclosed_by='"',
    skip_lines=1,
    columns=None,
    use_local=True,
):
    """
    Execute LOAD DATA INFILE to bulk import a file into a MySQL table.
    
    Uses parameterized approach where possible and strict validation
    for parts that cannot be parameterized in LOAD DATA INFILE.
    """
    # Validate inputs
    validated_path = validate_file_path(file_path)
    validated_table = validate_table_name(table_name)
    
    # Validate delimiters - only allow single safe characters
    allowed_delimiters = {',', '\t', '|', ';', ':', ' '}
    if field_delimiter not in allowed_delimiters:
        raise ValueError(f"Invalid field delimiter. Allowed: {allowed_delimiters}")
    
    if enclosed_by not in {'"', "'", ''}:
        raise ValueError("Invalid enclosed_by character. Allowed: '\"', \"'\", or empty string")
    
    if not isinstance(skip_lines, int) or skip_lines < 0:
        raise ValueError("skip_lines must be a non-negative integer")
    
    # Validate columns if provided
    if columns:
        for col in columns:
            if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', col):
                raise ValueError(f"Invalid column name: {col}")
    
    # Escape the file path for MySQL (escape backslashes and single quotes)
    mysql_safe_path = validated_path.replace('\\', '\\\\').replace("'", "\\'")
    
    # Build the LOAD DATA statement
    # Note: LOAD DATA INFILE does not support parameterized queries for file paths,
    # table names, or options. We rely on strict validation above.
    local_keyword = "LOCAL " if use_local else ""
    
    # Escape delimiter for MySQL
    field_delim_escaped = field_delimiter.replace('\\', '\\\\').replace("'", "\\'")
    enclosed_escaped = enclosed_by.replace('\\', '\\\\').replace("'", "\\'")
    
    query_parts = [
        f"LOAD DATA {local_keyword}INFILE '{mysql_safe_path}'",
        f"INTO TABLE `{validated_table}`",
        "CHARACTER SET utf8mb4",
        f"FIELDS TERMINATED BY '{field_delim_escaped}'",
    ]
    
    if enclosed_by:
        query_parts.append(f"OPTIONALLY ENCLOSED BY '{enclosed_escaped}'")
    
    query_parts.append("LINES TERMINATED BY '\\n'")
    
    if skip_lines > 0:
        query_parts.append(f"IGNORE {skip_lines} LINES")
    
    if columns:
        cols_str = ', '.join(f'`{col}`' for col in columns)
        query_parts.append(f"({cols_str})")
    
    query = '\n'.join(query_parts)
    
    cursor = connection.cursor()
    try:
        print(f"Executing bulk import:")
        print(f"  File: {validated_path}")
        print(f"  Table: {validated_table}")
        print(f"  Skip lines: {skip_lines}")
        print(f"  Field delimiter: {repr(field_delimiter)}")
        print(f"  Enclosed by: {repr(enclosed_by)}")
        print()
        
        cursor.execute(query)
        connection.commit()
        
        rows_affected = cursor.rowcount
        warnings = cursor.fetchwarnings() if hasattr(cursor, 'fetchwarnings') else []
        
        print(f"Import completed successfully!")
        print(f"  Rows imported: {rows_affected}")
        
        if warnings:
            print(f"  Warnings ({len(warnings)}):")
            for warning in warnings[:10]:  # Show first 10 warnings
                print(f"    {warning}")
            if len(warnings) > 10:
                print(f"    ... and {len(warnings) - 10} more warnings")
        
        return rows_affected
        
    except mysql.connector.Error as e:
        connection.rollback()
        print(f"Error during bulk import: {e}")
        raise
    finally:
        cursor.close()


